-- MoviesDekho production schema and 200-title seed
-- Import in phpMyAdmin or MySQL: SOURCE database/moviedekho_schema_seed.sql;

CREATE DATABASE IF NOT EXISTS moviedekho CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE moviedekho;

DROP TABLE IF EXISTS reviews;
DROP TABLE IF EXISTS watchlist;
DROP TABLE IF EXISTS movie_genres;
DROP TABLE IF EXISTS genres;
DROP TABLE IF EXISTS actresses;
DROP TABLE IF EXISTS users;
DROP TABLE IF EXISTS movies;

CREATE TABLE movies (
  id INT PRIMARY KEY,
  title VARCHAR(180) NOT NULL,
  slug VARCHAR(200) NOT NULL UNIQUE,
  type ENUM('movie','series') NOT NULL,
  genre VARCHAR(255) NOT NULL,
  release_year INT NOT NULL,
  duration VARCHAR(40) NOT NULL,
  seasons INT DEFAULT 0,
  episodes INT DEFAULT 0,
  rating DECIMAL(3,1) NOT NULL,
  imdb_rating DECIMAL(3,1) NOT NULL,
  metascore INT DEFAULT NULL,
  language VARCHAR(80) NOT NULL,
  country VARCHAR(100) NOT NULL,
  quality VARCHAR(40) NOT NULL,
  age_rating VARCHAR(20) NOT NULL,
  description TEXT NOT NULL,
  storyline TEXT NOT NULL,
  cast TEXT NOT NULL,
  director VARCHAR(160) NOT NULL,
  writer VARCHAR(160) NOT NULL,
  producer VARCHAR(160) NOT NULL,
  music_director VARCHAR(160) NOT NULL,
  trailer_url VARCHAR(255) NOT NULL,
  teaser_url VARCHAR(255) NOT NULL,
  poster_url VARCHAR(255) NOT NULL,
  backdrop_url VARCHAR(255) NOT NULL,
  thumbnail_url VARCHAR(255) NOT NULL,
  logo_url VARCHAR(255) NOT NULL,
  gallery_images TEXT NOT NULL,
  gradient_color VARCHAR(80) NOT NULL,
  streaming_platform VARCHAR(160) NOT NULL,
  views INT DEFAULT 0,
  likes INT DEFAULT 0,
  trending_score INT DEFAULT 0,
  featured TINYINT(1) DEFAULT 0,
  top_rated TINYINT(1) DEFAULT 0,
  recommended TINYINT(1) DEFAULT 0,
  release_date DATE NOT NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  INDEX idx_type (type),
  INDEX idx_release_year (release_year),
  INDEX idx_rating (imdb_rating),
  FULLTEXT INDEX ft_title_genre (title, genre, description)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE users (
  id INT AUTO_INCREMENT PRIMARY KEY,
  username VARCHAR(80) NOT NULL,
  email VARCHAR(140) NOT NULL UNIQUE,
  password VARCHAR(255) NOT NULL,
  avatar_url VARCHAR(255) DEFAULT NULL,
  bio VARCHAR(255) DEFAULT NULL,
  favorite_genres VARCHAR(255) DEFAULT NULL,
  theme_preference ENUM('dark','light') DEFAULT 'dark',
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE watchlist (
  id INT AUTO_INCREMENT PRIMARY KEY,
  user_id INT NOT NULL,
  movie_id INT NOT NULL,
  progress_percent INT DEFAULT 0,
  priority_label VARCHAR(40) DEFAULT 'Saved',
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  UNIQUE KEY unique_user_movie (user_id, movie_id),
  FOREIGN KEY (movie_id) REFERENCES movies(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE reviews (
  id INT AUTO_INCREMENT PRIMARY KEY,
  user_id INT NOT NULL,
  movie_id INT NOT NULL,
  rating INT NOT NULL,
  comment TEXT NOT NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (movie_id) REFERENCES movies(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE genres (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(80) NOT NULL UNIQUE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE movie_genres (movie_id INT NOT NULL, genre_id INT NOT NULL, PRIMARY KEY(movie_id, genre_id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE actresses (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(120), img VARCHAR(255), known_for VARCHAR(180)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;






SELECT m.id, g.id FROM movies m JOIN genres g ON FIND_IN_SET(g.name, REPLACE(m.genre, ', ', ',')) > 0;
